// UPDATED Extract Gmail Data JavaScript
// Handles both Gmail trigger and manual Gmail message fetch

let gmail = $input.first().json;

if (Array.isArray(gmail)) {
  gmail = gmail[0];
}

function extractEmail(emailObject) {
  if (!emailObject) return '';
  if (emailObject.text) return emailObject.text;
  if (emailObject.value && Array.isArray(emailObject.value) && emailObject.value.length > 0) {
    const firstValue = emailObject.value[0];
    if (firstValue.name && firstValue.address) {
      return `"${firstValue.name}" <${firstValue.address}>`;
    } else if (firstValue.address) {
      return firstValue.address;
    }
  }
  return String(emailObject);
}

function htmlToText(html) {
  if (!html) return '';
  let text = html;
  text = text.replace(/<br\s*\/?>/gi, '\n');
  text = text.replace(/<\/p>/gi, '\n\n');
  text = text.replace(/<\/div>/gi, '\n');
  text = text.replace(/<\/h[1-6]>/gi, '\n\n');
  text = text.replace(/<\/li>/gi, '\n');
  text = text.replace(/<\/tr>/gi, '\n');
  text = text.replace(/<\/td>/gi, ' ');
  text = text.replace(/<[^>]*>/g, '');
  text = text.replace(/&nbsp;/g, ' ');
  text = text.replace(/&amp;/g, '&');
  text = text.replace(/&lt;/g, '<');
  text = text.replace(/&gt;/g, '>');
  text = text.replace(/&quot;/g, '"');
  text = text.replace(/&#39;/g, "'");
  text = text.replace(/&apos;/g, "'");
  text = text.replace(/[ \t]+/g, ' ');
  text = text.replace(/\n[ \t]+/g, '\n');
  text = text.replace(/[ \t]+\n/g, '\n');
  text = text.replace(/\n{3,}/g, '\n\n');
  return text.trim();
}

function decodeBody(parts, mimeType = 'text/plain') {
  if (!parts) return null;
  const part = parts.find(p => p.mimeType === mimeType);
  if (part && part.body && part.body.data) {
    try {
      return Buffer.from(part.body.data, 'base64').toString('utf-8');
    } catch (error) {
      console.error('Error decoding body:', error);
      return null;
    }
  }
  return null;
}

const subject = gmail.subject || '';
const from = extractEmail(gmail.from);
const to = extractEmail(gmail.to);
const date = gmail.date || '';
const messageId = gmail.messageId || gmail.id;

let bodyText = null;

if (gmail.text) {
  bodyText = gmail.text;
} else if (gmail.html) {
  bodyText = htmlToText(gmail.html);
} else if (gmail.payload && gmail.payload.parts) {
  bodyText = decodeBody(gmail.payload.parts, 'text/plain');
  if (!bodyText) {
    const htmlBody = decodeBody(gmail.payload.parts, 'text/html');
    if (htmlBody) {
      bodyText = htmlToText(htmlBody);
    }
  }
}

if (!bodyText) {
  bodyText = gmail.snippet || '';
}

let labels = [];
if (Array.isArray(gmail.labels)) {
  labels = gmail.labels.map(label => {
    return typeof label === 'string' ? label : (label.name || label.id);
  });
} else if (Array.isArray(gmail.labelIds)) {
  labels = gmail.labelIds;
}

return {
  email_id: gmail.id,
  thread_id: gmail.threadId,
  subject: subject,
  from: from,
  to: to,
  date: date,
  message_id: messageId,
  body: bodyText,
  snippet: gmail.snippet || '',
  labels: labels,
  size_estimate: gmail.sizeEstimate,
  _original_gmail: gmail
};

const geminiOutput = $input.first().json;

let geminiResponse;
try {
  let responseText;

  if (Array.isArray(geminiOutput)) {
    responseText = geminiOutput[0].content.parts[0].text;
  } else if (geminiOutput.content && geminiOutput.content.parts) {
    responseText = geminiOutput.content.parts[0].text;
  } else {
    responseText = geminiOutput.text || geminiOutput.response || JSON.stringify(geminiOutput);
  }

  responseText = responseText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  geminiResponse = JSON.parse(responseText);

} catch (error) {
  console.error('Error parsing Gemini response:', error);
  geminiResponse = {
    classification: "OTHER",
    position: null,
    company: null,
    job_id: null,
    confidence: "low"
  };
}

const emailData = $('Extract Gmail Data').item.json;
geminiResponse.email_id = emailData.email_id;
geminiResponse.message_id = emailData.message_id;

return geminiResponse;

